<template><div class="page"><div class="header"><div><h1>注销业务管理</h1><p>人员注销和家庭户销户必须从专业入口创建，审批通过后显式执行。</p></div><div><el-button v-if="canPerson" type="primary" @click="open('PERSON')">人员注销申请</el-button><el-button v-if="canHousehold" type="danger" @click="open('HOUSEHOLD')">家庭户销户申请</el-button></div></div>
<el-alert v-if="error" title="注销记录加载失败" type="error" :closable="false" show-icon><el-button link type="primary" @click="load">重试</el-button></el-alert>
<el-card shadow="never"><el-table v-loading="loading" :data="records" empty-text="查询成功，暂无注销记录"><el-table-column prop="cancellationNo" label="注销编号" min-width="180"/><el-table-column prop="cancelObjectType" label="对象" width="100"/><el-table-column prop="personName" label="人员" width="110"/><el-table-column prop="householdNo" label="户号" min-width="130"/><el-table-column prop="cancelReasonCode" label="原因" min-width="150"/><el-table-column prop="eventDate" label="日期" width="120"/><el-table-column prop="businessStatus" label="状态" min-width="110"/><el-table-column label="申请" width="90"><template #default="{row}"><el-button link type="primary" @click="$router.push(`/applications/${row.applicationId}`)">查看</el-button></template></el-table-column></el-table><AppPagination v-model:current="query.current" v-model:size="query.size" :total="total" @change="load"/></el-card>
<FormDialog v-model:visible="visible" :title="kind==='PERSON'?'人员注销申请':'家庭户销户申请'" :loading="submitting" @confirm="submit"><el-form ref="formRef" :model="form" :rules="rules" label-width="110px"><el-form-item v-if="kind==='PERSON'" label="人员" prop="personId"><PersonSelect v-model="form.personId"/></el-form-item><el-form-item v-else label="家庭户 ID" prop="householdId"><el-input-number v-model="form.householdId" :min="1"/></el-form-item><el-form-item label="注销原因" prop="cancelReasonCode"><el-select v-model="form.cancelReasonCode"><el-option v-for="x in reasons" :key="x" :label="x" :value="x"/></el-select></el-form-item><el-form-item label="事件日期" prop="eventDate"><el-date-picker v-model="form.eventDate" value-format="YYYY-MM-DD"/></el-form-item><el-form-item label="申请标题" prop="title"><el-input v-model.trim="form.title"/></el-form-item><el-form-item label="申请理由" prop="reason"><el-input v-model.trim="form.reason" type="textarea"/></el-form-item></el-form></FormDialog></div></template>
<script setup>
import { computed,onMounted,reactive,ref } from 'vue';import { useRouter } from 'vue-router';import { ElMessage } from 'element-plus';import FormDialog from '../../components/common/FormDialog.vue';import AppPagination from '../../components/common/AppPagination.vue';import PersonSelect from '../../components/business/PersonSelect.vue';import { createHouseholdCancellation,createPersonCancellation,getCancellationPage } from '../../api/cancellations.js';import { normalizePageResult } from '../../utils/page.js';import { useUserStore } from '../../stores/user.js';import { PERMISSIONS } from '../../constants/permissions.js'
const router=useRouter(),user=useUserStore();const canPerson=computed(()=>user.hasPermission(PERMISSIONS.CANCELLATION_PERSON_CREATE)),canHousehold=computed(()=>user.hasPermission(PERMISSIONS.CANCELLATION_HOUSEHOLD_CREATE));const reasons=['DEATH','DECLARED_DEAD','SETTLED_ABROAD','DUPLICATE_REGISTRATION','NO_ACTIVE_MEMBERS','HOUSEHOLD_MERGED','ADDRESS_INVALIDATED','OTHER_APPROVED'];const query=reactive({current:1,size:10});const records=ref([]),total=ref(0),loading=ref(false),error=ref(false),visible=ref(false),submitting=ref(false),kind=ref('PERSON'),formRef=ref();const form=reactive({personId:null,householdId:null,cancelReasonCode:'',eventDate:'',title:'',reason:'',cancelReasonDetail:'',remark:''});const rules={personId:[{required:true,message:'请选择人员'}],householdId:[{required:true,message:'请输入家庭户 ID'}],cancelReasonCode:[{required:true,message:'请选择原因'}],eventDate:[{required:true,message:'请选择日期'}],title:[{required:true,message:'请输入标题'}],reason:[{required:true,message:'请输入理由'}]}
async function load(){loading.value=true;try{const p=normalizePageResult(await getCancellationPage(query));records.value=p.records;total.value=p.total;error.value=false}catch{error.value=true}finally{loading.value=false}}function open(type){kind.value=type;Object.assign(form,{personId:null,householdId:null,cancelReasonCode:'',eventDate:'',title:type==='PERSON'?'人员注销申请':'家庭户销户申请',reason:'',cancelReasonDetail:'',remark:''});visible.value=true}async function submit(){if(!await formRef.value?.validate())return;submitting.value=true;try{const data={cancelReasonCode:form.cancelReasonCode,cancelReasonDetail:form.cancelReasonDetail||null,eventDate:form.eventDate,title:form.title,reason:form.reason,remark:form.remark||null};const created=kind.value==='PERSON'?await createPersonCancellation({...data,personId:form.personId,newHeadPersonId:null}):await createHouseholdCancellation({...data,householdId:form.householdId});ElMessage.success('专业申请已创建，请上传材料后提交审批');visible.value=false;router.push(`/applications/${created.applicationId}`)}finally{submitting.value=false}}onMounted(load)
</script><style scoped>.page{display:flex;flex-direction:column;gap:16px}.header{display:flex;justify-content:space-between;align-items:flex-end}.header h1{margin:0 0 6px}.header p{color:var(--el-text-color-secondary)}</style>
